#=================REGION=====================================	
	LAYER		
		NAME 'REG' 
		TYPE POLYGON
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo
		INCLUDE "datashare.inc"
		#PROCESSING "NATIVE_FILTER=%regionFilter%"
		DATA 'sp_geometry FROM "vw_region_boundary_map" USING UNIQUE region_id USING srid=4326'
		FILTER  (%regionFilter% )
		VALIDATION		
			'regionFilter'   '.*'				
		END
		METADATA
			'ows_title' 'Region'
		END
		STATUS OFF	
		TRANSPARENCY 50
		PROJECTION
			'proj=longlat'  
			'datum=WGS84'
			'no_defs'
		END
		CLASS
			NAME 'Region' 
			STYLE
				WIDTH 6
				OUTLINECOLOR 255 0 0
				COLOR -1 -1 -1
			END
		END
	END
# ========== PROVINCE================================= 
