	LAYER
		NAME 'TRH'
		TYPE LINE
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo
		#EXTENT 72.504366 18.900959 73.403214 19.320367
		INCLUDE "datashare.inc"
		DATA 'sp_geometry FROM "vw_att_details_trench_map" USING UNIQUE system_id USING srid=4326' 
