		END
		STATUS OFF
		GROUP 'Network1'
		TRANSPARENCY 100
		PROJECTION
			'proj=longlat'
			'datum=WGS84'
			'no_defs'
		END
		CLASSITEM 'count_ducts' 
		CLASS 
			NAME "count_ducts"
			TEXT "[count_ducts]"
			EXPRESSION "count_ducts"
			STYLE
				WIDTH 10
				COLOR 255 0 0
				LINECAP ROUND
				PATTERN 10 10 END
			END
			LABEL
				FONT arial
				TYPE truetype
				COLOR 255 255 255
				#COLOR  255 0 0
				SIZE 16
				STYLE
					GEOMTRANSFORM 'labelpoly'
					COLOR 255 0 0  # background rect.
				END
				STYLE
					GEOMTRANSFORM 'labelunderline'
					COLOR   0 0 255 # underline
					OFFSET 	0 -2 	# with some offset
				END
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
			END
		END
		CLASS 
			NAME "Out_Of_Range"   
			TEXT "[count_ducts]"
			STYLE
				WIDTH 10
				COLOR 255 0 0
				LINECAP ROUND
				PATTERN 10 10 END
