	LAYER
		NAME 'FAU'
		TYPE POINT
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo 
		INCLUDE "datashare.inc"	
		DATA 'sp_geometry FROM vw_att_details_fault_map USING UNIQUE system_id USING srid=4326'	
		FILTER  (%provinceFilter% AND (%faultFilter% ))
		
		VALIDATION		
			'provinceFilter'   '.*'	
			'faultFilter'   '.*'
