		METADATA
			'ows_title' 'Fault'
		END
		STATUS OFF
		GROUP 'Network'		
		CLASS
			NAME 'Fault'
            EXPRESSION ('[fault_status]'  eq 'Temporary Resolved')  			
			STYLE
				SYMBOL "icons/Fault/temporary_resolved.png" 
				SIZE 42
				OFFSET 0 -10
			END
            			
		END
		CLASS
			NAME 'Fault'
            EXPRESSION ('[fault_status]'  eq 'Reopened')  			
			STYLE
				SYMBOL "icons/Fault/reopened.png" 
				SIZE 42	
				OFFSET 0 -10
			END
            			
		END
		CLASS
			NAME 'Fault'
            EXPRESSION ('[fault_status]'  eq 'Unresolved')  			
			STYLE
				SYMBOL "icons/Fault/unresolved.png" 
				SIZE 42
				OFFSET 0 -10				
			END
            			
		END	
CLASS
			NAME 'Fault'
