				WIDTH 4
				COLOR 150 0 0				                					
				PATTERN 10 5  END
			END		
			LABEL
				FONT arial
				TYPE truetype
				COLOR 255 255 255				
				SIZE 16
				STYLE
					GEOMTRANSFORM 'labelpoly'
					COLOR 150 0 0  # background rect.
				END
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
			END
		END	
		 CLASS 
			EXPRESSION ('[network_status]'  eq 'D')					
		     STYLE
				WIDTH 4
				COLOR 0 0 255				                					
				PATTERN 10 5  END
			END		
			LABEL
				FONT arial
				TYPE truetype
				COLOR 255 255 255				
				SIZE 16
				STYLE
					GEOMTRANSFORM 'labelpoly'
					COLOR 150 0 0  # background rect.
				END
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
			END
		END
		CLASS 
			EXPRESSION ('[network_status]'  eq 'A')					
		     STYLE
				WIDTH 4
				COLOR 0 200 0				                					
				PATTERN 10 5  END
			END		
			LABEL
				FONT arial
				TYPE truetype
				COLOR 255 255 255				
				SIZE 16
				STYLE
					GEOMTRANSFORM 'labelpoly'
					COLOR 150 0 0  # background rect.
				END
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
			END
		END		
	END
	
	# ===============================MICRO DUCT=========================================== 
	LAYER
		NAME 'MD'
		TYPE LINE
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo
		#EXTENT 72.504366 18.900959 73.403214 19.320367
		INCLUDE "datashare.inc"
		DATA 'sp_geometry FROM "vw_att_details_microduct_map" USING UNIQUE system_id USING srid=4326' 
		FILTER (%provinceFilter% AND (%layerFilter% ) AND (%ownershipFilter%) )
		
		VALIDATION		
			'provinceFilter'   '.*'	
            'layerFilter'   '.*'
			'ownershipFilter'   '.*'			
		END 	
		METADATA
			'ows_title' 'Microduct'
		END
		STATUS OFF
		GROUP 'Network1'
		TRANSPARENCY 100
		PROJECTION
			'proj=longlat'
			'datum=WGS84'
			'no_defs'
		END
		CLASS
			STYLE
				WIDTH 4
         	COLOR 0 120 0
	    	LINECAP ROUND
         	PATTERN 10 10 END
			END
		END
	END
	
